def gen(rng, size):
    total = max(1, min(size, 200000))
    m = max(1, min(300, int(total ** 0.5) or 1))
    n = max(1, min(200000, total // m))
    board = []
    for _ in range(m):
        row = []
        for _ in range(n):
            r = rng.random()
            if r < 0.3:
                row.append('#')
            elif r < 0.6:
                row.append(' ')
            else:
                row.append(rng.choice('abcdefghijklmnopqrstuvwxyz'))
        board.append(row)
    max_dim = max(m, n)
    length = rng.randint(1, max_dim)
    word = ''.join(rng.choice('abcdefghijklmnopqrstuvwxyz') for _ in range(length))
    return [board, word]

