class Solution:
    def placeWordInCrossword(self, board, word):
        m, n = len(board), len(board[0])
        L = len(word)
        candidates = [word, word[::-1]]
        def matches(segment, w):
            if len(segment) != L:
                return False
            for a, b in zip(segment, w):
                if a != ' ' and a != b:
                    return False
            return True
        lines = []
        for r in range(m):
            lines.append(''.join(board[r]))
        for c in range(n):
            lines.append(''.join(board[r][c] for r in range(m)))
        for line in lines:
            for seg in line.split('#'):
                for w in candidates:
                    if matches(seg, w):
                        return True
        return False

