class Solution:
    def placeWordInCrossword(self, board, word):
        m = len(board)
        n = len(board[0])
        L = len(word)
        rev = word[::-1]
        def check_line(line):
            i = 0
            size = len(line)
            while i < size:
                if line[i] == '#':
                    i += 1
                    continue
                j = i
                while j < size and line[j] != '#':
                    j += 1
                if j - i == L:
                    for w in (word, rev):
                        ok = True
                        for k in range(L):
                            c = line[i + k]
                            if c != ' ' and c != w[k]:
                                ok = False
                                break
                        if ok:
                            return True
                i = j
            return False
        for r in range(m):
            if check_line(board[r]):
                return True
        for c in range(n):
            col = [board[r][c] for r in range(m)]
            if check_line(col):
                return True
        return False

