var placeWordInCrossword = function(board, word) {
    const m = board.length;
    const n = board[0].length;
    const L = word.length;
    const rev = word.split('').reverse().join('');
    function checkLine(line) {
        const size = line.length;
        let i = 0;
        while (i < size) {
            if (line[i] === '#') { i++; continue; }
            let j = i;
            while (j < size && line[j] !== '#') j++;
            if (j - i === L) {
                for (const w of [word, rev]) {
                    let ok = true;
                    for (let k = 0; k < L; k++) {
                        const c = line[i + k];
                        if (c !== ' ' && c !== w[k]) { ok = false; break; }
                    }
                    if (ok) return true;
                }
            }
            i = j;
        }
        return false;
    }
    for (let r = 0; r < m; r++) {
        if (checkLine(board[r])) return true;
    }
    for (let c = 0; c < n; c++) {
        const col = [];
        for (let r = 0; r < m; r++) col.push(board[r][c]);
        if (checkLine(col)) return true;
    }
    return false;
};
